#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        printf("Fork failed!\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child Process: PID = %d, Parent PID = %d\n", 
               getpid(), getppid());
        printf("Child executing...\n");
        _exit(0);
    }
    else {
        // Parent process
        printf("Parent Process: PID = %d, Child PID = %d\n", 
               getpid(), pid);
        wait(NULL); // Wait for child to complete
        printf("Child completed, parent continuing\n");
    }
    return 0;
}

#include <stdio.h>
#include <pthread.h>
#include <unistd.h>

// Shared variable
int shared_counter = 0;
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

// Thread function
void* thread_function(void* arg) {
    int thread_id = *(int*)arg;

    for (int i = 0; i < 5; i++) {
        pthread_mutex_lock(&mutex); // Enter critical section
        shared_counter++;
        printf("Thread %d: Counter = %d\n", thread_id, shared_counter);
        pthread_mutex_unlock(&mutex); // Exit critical section
        usleep(100000); // Sleep 100ms
    }

    return NULL;
}

int main() {
    pthread_t threads[3];
    int thread_ids[3] = {1, 2, 3};

    printf("Creating 3 threads...\n");

    // Create threads
    for (int i = 0; i < 3; i++) {
        pthread_create(&threads[i], NULL, thread_function, &thread_ids[i]);
    }

    // Wait for all threads to complete
    for (int i = 0; i < 3; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("Final counter value: %d\n", shared_counter);
    printf("All threads completed\n");

    return 0;
}

// WRITER PROCESS (process1.c)
#include <stdio.h>
#include <sys/ipc.h>
#include <sys/shm.h>
#include <string.h>

int main() {
    key_t key = ftok("shmfile", 65); // Generate unique key
    int shmid = shmget(key, 1024, IPC_CREAT | 0666); // Create shared memory
    char *str = (char*)shmat(shmid, (void*)0, 0); // Attach to shared memory

    printf("Writer: Enter message: ");
    fgets(str, 1024, stdin);

    printf("Writer: Message written to shared memory\n");
    shmdt(str); // Detach shared memory

    return 0;
}

// READER PROCESS (process2.c)
#include <stdio.h>
#include <sys/ipc.h>
#include <sys/shm.h>

int main() {
    key_t key = ftok("shmfile", 65);
    int shmid = shmget(key, 1024, 0666); // Get existing shared memory
    char *str = (char*)shmat(shmid, (void*)0, 0); // Attach

    printf("Reader: Message read from shared memory: %s", str);
    shmdt(str); // Detach

    // Destroy shared memory
    shmctl(shmid, IPC_RMID, NULL);

    return 0;
}
